What will be the output of the following code?
int sum = 0;
for(int i = 1; i <= 10; i++) {
    sum += i;
}
printf("%d", sum);

What is the output?
int i = 5;
while(i > 0) {
    printf("%d ", i);
    i--;
}

What will be printed?
for(int i = 0; i < 3; i++) {
    for(int j = 0; j < 2; j++) {
        printf("%d%d ", i, j);
    }
}

What is the output?
int i = 1;
do {
    printf("%d ", i);
    i++;
} while(i <= 3);

